using sv_752731f0188347e08cd6817479683432.Models;

namespace sv_752731f0188347e08cd6817479683432.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

using sv_752731f0188347e08cd6817479683432.Models;

namespace sv_752731f0188347e08cd6817479683432.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 30),
            new(2, "Margherita Pizza", "Neapolitan pizza with San Marzano tomatoes, mozzarella, and fresh basil.", 45),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken chunks in a creamy spiced tomato sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cheese and aromatic spices.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, onion, and cilantro.", 55),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken and covered in tangy green salsa.", 45),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return RecipesByCuisine.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@using sv_752731f0188347e08cd6817479683432.Models
@using sv_752731f0188347e08cd6817479683432.Services
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
    }

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr>
                    <th>Title</th>
                    <th>Description</th>
                    <th>Prep Time (min)</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var recipe in DisplayedRecipes)
                {
                    <tr>
                        <td>@recipe.Title</td>
                        <td>@recipe.Description</td>
                        <td>@recipe.PrepTimeMinutes</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _error;

    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IReadOnlyList<Recipe> DisplayedRecipes =>
        string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes!.OrderBy(r => r.PrepTimeMinutes).ToList()
            : _recipes!.OrderByDescending(r => r.Id).ToList();

    protected override Task OnParametersSetAsync()
    {
        // Only reload when the cuisine changes, not when sort changes.
        if (CuisineId == _loadedCuisineId)
        {
            return Task.CompletedTask;
        }

        return LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load.
        await CancelPendingLoadAsync();

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Guard against a stale callback after cancellation.
            if (cts.Token.IsCancellationRequested)
            {
                return;
            }

            _recipes = results;
        }
        catch (OperationCanceledException)
        {
            // Load was superseded or the component is disposing — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingLoadAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

